#!/usr/bin/env python3
# This file was generated by Cursor AI on 2026-05-10.
"""
Write the paper-style LaTeX table (``table.tex``) from eqsat benchmark JSON results.
Also prints the same two tables to stdout as ASCII bordered tables.

Regenerates metric-specific virtual-best JSON files and ``virtual_best_scq.json`` via
``virtual_best.write_virtual_best_per_metric`` / ``write_virtual_best``, like
``report_results.py``, before loading results.

This mirrors the LaTeX output of ``report_results.py`` without running summaries or
percent tables.

Usage:
    python3 latex_table.py [RESULTS_DIR]

Default RESULTS_DIR is this script's directory joined with ``../results``.
"""

from __future__ import annotations

import sys
from pathlib import Path
from typing import Any

from virtual_best import (
    VIRTUAL_BEST_BASENAME,
    VIRTUAL_BEST_METRIC_TO_BASENAME,
    load_by_filename,
    write_virtual_best,
    write_virtual_best_per_metric,
)

from report_results import (
    PAR2_TIMEOUT_SECONDS,
    count_timeouts_memouts,
    mean_metric,
    median_metric,
    mean_sum_metrics,
    par2_score,
)

LATEX_METHOD_LABELS = {
    "ilp_ac.json": "I-AC",
    "ilp_no_ac.json": "I-No-AC",
    "greedy_ac.json": "G-AC",
    "greedy_no_ac.json": "G-No-AC",
    VIRTUAL_BEST_BASENAME: "VB",
}

LATEX_METHOD_ORDER = (
    "ilp_ac.json",
    "ilp_no_ac.json",
    "greedy_ac.json",
    "greedy_no_ac.json",
    VIRTUAL_BEST_BASENAME,
)

TIMING_METHOD_ORDER = (
    "ilp_ac.json",
    "ilp_no_ac.json",
    "greedy_ac.json",
    "greedy_no_ac.json",
)


def is_numeric(x: Any) -> bool:
    return isinstance(x, (int, float)) and not isinstance(x, bool)


def fmt_latex_time(x: float, digits: int = 3) -> str:
    if x != x:
        return "N/A"
    return f"{x:.{digits}f}s"


def fmt_latex_diff(x: float, digits: int = 2) -> str:
    if x != x:
        return "N/A"
    return f"{x:.{digits}f}"


def fmt_latex_median(x: float) -> str:
    if x != x:
        return "N/A"
    rounded = round(x)
    if abs(x - rounded) < 1e-9:
        return f"{int(rounded)}"
    return f"{x:.1f}"


def cell_to_latex(cell: str) -> str:
    """Turn ASCII table cell text into a LaTeX tabular cell (escape %)."""
    return cell.replace("%", "\\%")


def _ascii_horiz(widths: list[int]) -> str:
    return "+" + "+".join("-" * (w + 2) for w in widths) + "+"


def _ascii_data_line(cells: list[str], widths: list[int]) -> str:
    parts: list[str] = ["| ", cells[0].ljust(widths[0])]
    for j in range(1, len(cells)):
        parts.append(" | ")
        parts.append(cells[j].ljust(widths[j]))
    parts.append(" |")
    return "".join(parts)


def _ascii_span_inner_width(widths: list[int], lo: int, hi_exclusive: int) -> int:
    """Width for a merged header label over columns ``lo .. hi_exclusive-1`` (inter-column `` | `` only)."""
    if lo >= hi_exclusive:
        return 0
    n = hi_exclusive - lo
    return sum(widths[lo:hi_exclusive]) + 3 * max(0, n - 1)


def _ascii_centered(label: str, width: int) -> str:
    if width <= 0:
        return ""
    label = label[:width]
    pad = width - len(label)
    left = pad // 2
    return " " * left + label + " " * (pad - left)


def _ascii_column_widths(subheaders: tuple[str, ...], rows: list[list[str]]) -> list[int]:
    ncols = len(subheaders)
    data: list[list[str]] = [list(subheaders), *[list(r) for r in rows]]
    return [max(len(data[i][j]) for i in range(len(data))) for j in range(ncols)]


def _ascii_two_line_grouped_table(
    groups: list[tuple[str, int]],
    subheaders: tuple[str, ...],
    rows: list[list[str]],
    method_label: str = "Method",
) -> str:
    """
    ASCII table with a two-line header: ``Method`` spans both lines in column 0;
    top line has group labels spanning ``(label, colspan)`` over columns 1..end.
    """
    if sum(span for _, span in groups) != len(subheaders) - 1:
        raise ValueError("group colspans must sum to len(subheaders) - 1 (excluding Method column)")
    widths = _ascii_column_widths(subheaders, rows)
    widths[0] = max(widths[0], len(method_label))

    lines: list[str] = []
    hline = _ascii_horiz(widths)
    lines.append(hline)

    row0_parts: list[str] = ["| ", method_label.ljust(widths[0])]
    lo = 1
    for glabel, span in groups:
        inner_w = _ascii_span_inner_width(widths, lo, lo + span)
        row0_parts.append(" | ")
        row0_parts.append(_ascii_centered(glabel, inner_w))
        lo += span
    row0_parts.append(" |")
    lines.append("".join(row0_parts))

    row1_cells = [subheaders[j].ljust(widths[j]) for j in range(len(subheaders))]
    lines.append(_ascii_data_line(row1_cells, widths))

    lines.append(hline)
    for row in rows:
        lines.append(_ascii_data_line(list(row), widths))
    lines.append(hline)
    return "\n".join(lines)


MAIN_ASCII_SUBHEADERS = (
    "",  # rowspan with "Method" on line above
    "avg",
    "med",
    "# min",
    "avg %",
    "avg % >0",
    "# <0%",
    "# =0%",
    "# >0%",
    "avg",
    "med",
    "avg",
    "med",
)

MAIN_ASCII_GROUPS = [
    ("memdag", 3),
    ("Δ vs baseline", 5),
    ("r2u2 instr", 2),
    ("sabre", 2),
]

TIMING_ASCII_SUBHEADERS = ("", "avg (MO)", "avg (TO)", "avg")

TIMING_ASCII_GROUPS = [("Egglog", 1), ("Gurobi", 1), ("Par-2", 1)]


def unique_scq_win_counts_for_table(
    control_map: dict[str, dict[str, Any]],
    variant_maps: dict[str, dict[str, Any]],
) -> dict[str, int]:
    run_maps: dict[str, dict[str, dict[str, Any]]] = {"control.json": control_map}
    for basename in LATEX_METHOD_ORDER:
        # Exclude virtual-best from strict-winner comparisons: VB is constructed as the per-formula
        # min across runs, so it always ties the best real method and would force all counts to 0.
        if basename == VIRTUAL_BEST_BASENAME:
            continue
        m = variant_maps.get(basename)
        if m is not None:
            run_maps[basename] = m

    available = tuple(run_maps.keys())
    if len(available) < 2:
        counts = {b: 0 for b in available}
        counts.setdefault(VIRTUAL_BEST_BASENAME, 0)
        return counts

    common_filenames = set(run_maps[available[0]])
    for basename in available[1:]:
        common_filenames &= set(run_maps[basename])

    counts = {basename: 0 for basename in available}
    for filename in sorted(common_filenames):
        values: dict[str, float] = {}
        for basename in available:
            scq = run_maps[basename][filename].get("scq")
            if not is_numeric(scq):
                break
            assert isinstance(scq, (int, float))
            values[basename] = float(scq)
        if len(values) != len(available):
            continue
        best_scq = min(values.values())
        winners = [b for b, s in values.items() if s == best_scq]
        if len(winners) != 1:
            continue
        counts[winners[0]] += 1
    counts.setdefault(VIRTUAL_BEST_BASENAME, 0)
    return counts


def avg_scq_reduction_vs_baseline(
    baseline_map: dict[str, dict[str, Any]],
    variant_map: dict[str, dict[str, Any]],
) -> tuple[float, float, int, int, int]:
    reductions: list[float] = []
    positive_reductions: list[float] = []
    n_positive = 0
    n_equal_zero = 0
    n_negative = 0

    common_filenames = set(baseline_map.keys()) & set(variant_map.keys())
    for filename in common_filenames:
        baseline_scq = baseline_map[filename].get("scq")
        variant_scq = variant_map[filename].get("scq")
        if not (is_numeric(baseline_scq) and is_numeric(variant_scq)):
            continue
        assert isinstance(baseline_scq, (int, float))
        assert isinstance(variant_scq, (int, float))
        if baseline_scq <= 0:
            continue
        reduction = ((float(baseline_scq) - float(variant_scq)) / float(baseline_scq)) * 100.0
        reductions.append(reduction)
        if reduction > 0:
            n_positive += 1
            positive_reductions.append(reduction)
        if reduction == 0:
            n_equal_zero += 1
        elif reduction < 0:
            n_negative += 1

    if not reductions:
        return (float("nan"), float("nan"), 0, 0, 0)
    avg_reduction = sum(reductions) / len(reductions)
    avg_positive_reduction = (
        (sum(positive_reductions) / len(positive_reductions))
        if positive_reductions
        else float("nan")
    )
    return (avg_reduction, avg_positive_reduction, n_positive, n_equal_zero, n_negative)


def write_latex_tables(
    results_dir: Path,
    control_map: dict[str, dict[str, Any]],
    variant_maps: dict[str, dict[str, Any]],
    virtual_best_by_metric: dict[str, dict[str, dict[str, Any]]],
    timeout_summary: dict[str, tuple[float, int, int, float, int, int, float]],
) -> Path:
    out_path = results_dir / "table.tex"
    unique_scq_wins = unique_scq_win_counts_for_table(control_map, variant_maps)
    main_rows: list[list[str]] = []
    timing_rows: list[list[str]] = []

    ctrl_scq_avg = mean_metric(control_map, "scq")
    ctrl_scq_med = median_metric(control_map, "scq")
    ctrl_instr_avg = mean_metric(control_map, "num-tl-instructions")
    ctrl_instr_med = median_metric(control_map, "num-tl-instructions")
    ctrl_sabre_avg = mean_metric(control_map, "sabre-total-bytes")
    ctrl_sabre_med = median_metric(control_map, "sabre-total-bytes")
    ctrl_unique = unique_scq_wins.get("control.json", 0)
    (
        ctrl_reduction_avg,
        ctrl_reduction_pos_avg,
        ctrl_reduction_pos,
        ctrl_reduction_eq_zero,
        ctrl_reduction_neg,
    ) = avg_scq_reduction_vs_baseline(
        control_map, control_map
    )
    main_rows.append(
        [
            "Baseline",
            fmt_latex_diff(ctrl_scq_avg),
            fmt_latex_median(ctrl_scq_med),
            str(ctrl_unique),
            f"{fmt_latex_diff(ctrl_reduction_avg)}%",
            f"{fmt_latex_diff(ctrl_reduction_pos_avg)}%",
            str(ctrl_reduction_pos),
            str(ctrl_reduction_eq_zero),
            str(ctrl_reduction_neg),
            fmt_latex_diff(ctrl_instr_avg),
            fmt_latex_median(ctrl_instr_med),
            fmt_latex_diff(ctrl_sabre_avg),
            fmt_latex_median(ctrl_sabre_med),
        ]
    )

    for basename in LATEX_METHOD_ORDER:
        var_map = variant_maps.get(basename)
        if var_map is None:
            continue
        method = LATEX_METHOD_LABELS.get(basename, basename)
        (
            egglog_avg_time,
            _egglog_to,
            egglog_mo,
            gurobi_avg_time,
            gurobi_to,
            _gurobi_mo,
            par2_score_value,
        ) = timeout_summary.get(
            basename, (float("nan"), 0, 0, float("nan"), 0, 0, float("nan"))
        )

        # For virtual_best row, use the per-metric virtual-best file when available.
        scq_map = virtual_best_by_metric.get("scq", var_map) if basename == VIRTUAL_BEST_BASENAME else var_map
        instr_map = (
            virtual_best_by_metric.get("num-tl-instructions", var_map)
            if basename == VIRTUAL_BEST_BASENAME
            else var_map
        )
        sabre_map = (
            virtual_best_by_metric.get("sabre-total-bytes", var_map)
            if basename == VIRTUAL_BEST_BASENAME
            else var_map
        )

        avg_scq = mean_metric(scq_map, "scq")
        med_scq = median_metric(scq_map, "scq")
        avg_instr = mean_metric(instr_map, "num-tl-instructions")
        med_instr = median_metric(instr_map, "num-tl-instructions")
        avg_sabre = mean_metric(sabre_map, "sabre-total-bytes")
        med_sabre = median_metric(sabre_map, "sabre-total-bytes")
        n_unique: str | int = unique_scq_wins.get(basename, 0)
        if basename == VIRTUAL_BEST_BASENAME:
            n_unique = "N/A"
        avg_reduction, avg_positive_reduction, n_positive, n_equal_zero, n_negative = avg_scq_reduction_vs_baseline(
            control_map, scq_map
        )

        main_rows.append(
            [
                method,
                fmt_latex_diff(avg_scq),
                fmt_latex_median(med_scq),
                str(n_unique),
                f"{fmt_latex_diff(avg_reduction)}%",
                f"{fmt_latex_diff(avg_positive_reduction)}%",
                str(n_positive),
                str(n_equal_zero),
                str(n_negative),
                fmt_latex_diff(avg_instr),
                fmt_latex_median(med_instr),
                fmt_latex_diff(avg_sabre),
                fmt_latex_median(med_sabre),
            ]
        )

        egglog_str = f"{fmt_latex_time(egglog_avg_time)} ({egglog_mo})"
        if basename in ("greedy_ac.json", "greedy_no_ac.json"):
            gurobi_str = "N/A"
        else:
            gurobi_str = f"{fmt_latex_time(gurobi_avg_time)} ({gurobi_to})"
        par2_str = fmt_latex_time(par2_score_value)
        if basename in TIMING_METHOD_ORDER:
            timing_rows.append([method, egglog_str, gurobi_str, par2_str])

    lines: list[str] = [
        r"\begin{tabular}{|l|c|c|c|c|c|c|c|c|c|c|c|c|}",
        r"\hline",
        (
            r"\multirow{2}{*}{\textbf{Method}} & "
            r"\multicolumn{3}{c|}{\textbf{\memdag}} & "
            r"\multicolumn{5}{c|}{\textbf{$\Delta$ \memdag{} vs Baseline}} & "
            r"\multicolumn{2}{c|}{\textbf{\# \rruu Instr.}} & "
            r"\multicolumn{2}{c|}{\textbf{\# \sabre Bytes}} \\"
        ),
        r"\cline{2-13}",
        r"& \textbf{avg} & \textbf{median} & \textbf{\# min} & \textbf{avg \%} & \textbf{avg \% $>0\%$} & \textbf{\# $<0\%$} & \textbf{\# $=0\%$} & \textbf{\# $>0\%$} & \textbf{avg} & \textbf{median} & \textbf{avg} & \textbf{median} \\",
        r"\hline",
        r"\hline",
    ]

    for row in main_rows:
        latex_cells = [cell_to_latex(c) for c in row]
        lines.append(" & ".join(latex_cells) + r" \\")
        lines.append(r"\hline")

    lines.extend(
        [
            r"\end{tabular}",
            "",
            r"\begin{tabular}{|l|c|c|c|}",
            r"\hline",
            r"\multirow{2}{*}{\textbf{Method}} & \textbf{Egglog Time} & \textbf{Gurobi Time} & \textbf{Par-2 Score} \\",
            r"\cline{2-4}",
            r"& \textbf{avg (\# MO)} & \textbf{avg (\# TO)} & \textbf{avg} \\",
            r"\hline",
            r"\hline",
        ]
    )

    for row in timing_rows:
        latex_cells = [cell_to_latex(c) for c in row]
        lines.append(" & ".join(latex_cells) + r" \\")
        lines.append(r"\hline")

    lines.append(r"\end{tabular}")
    out_path.write_text("\n".join(lines) + "\n", encoding="utf-8")

    ascii_main = _ascii_two_line_grouped_table(MAIN_ASCII_GROUPS, MAIN_ASCII_SUBHEADERS, main_rows)
    ascii_timing = _ascii_two_line_grouped_table(TIMING_ASCII_GROUPS, TIMING_ASCII_SUBHEADERS, timing_rows)
    print(f"{ascii_main}\n\n{ascii_timing}", file=sys.stdout)

    return out_path


def main() -> int:
    script_dir = Path(__file__).resolve().parent
    results_dir = Path(sys.argv[1]) if len(sys.argv) > 1 else script_dir.parent / "results"
    results_dir = results_dir.resolve()

    if not results_dir.is_dir():
        print(f"Not a directory: {results_dir}", file=sys.stderr)
        return 1

    control_path = results_dir / "control.json"
    if not control_path.is_file():
        print(f"Missing {control_path}", file=sys.stderr)
        return 1

    vb_written = write_virtual_best_per_metric(results_dir)
    if not vb_written:
        print(
            "Warning: metric-specific virtual-best files not regenerated (see virtual_best messages); "
            "using existing files if present.",
            file=sys.stderr,
        )
    vb_out = write_virtual_best(results_dir)
    if vb_out is None:
        print(
            f"Warning: {VIRTUAL_BEST_BASENAME} not regenerated; using existing file if present.",
            file=sys.stderr,
        )

    control_map = load_by_filename(control_path)

    virtual_best_by_metric: dict[str, dict[str, dict[str, Any]]] = {}
    for metric, basename in VIRTUAL_BEST_METRIC_TO_BASENAME.items():
        path = results_dir / basename
        if path.is_file():
            virtual_best_by_metric[metric] = load_by_filename(path)

    variant_maps: dict[str, dict[str, Any]] = {}
    timeout_summary_by_name: dict[str, tuple[float, int, int, float, int, int, float]] = {}

    for basename in LATEX_METHOD_ORDER:
        path = results_dir / basename
        if not path.is_file():
            print(f"Warning: missing results file, skipping LaTeX row: {path}", file=sys.stderr)
            continue
        by_fn = load_by_filename(path)
        variant_maps[basename] = by_fn

        if basename == VIRTUAL_BEST_BASENAME:
            continue

        counts = count_timeouts_memouts(by_fn)
        egglog_avg_time = mean_sum_metrics(
            by_fn,
            ("egglog-encoding-time", "egglog-solver-time"),
            allow_negative=False,
        )
        gurobi_avg_time = mean_sum_metrics(
            by_fn,
            ("gurobi-encoding-time", "gurobi-solving-time"),
            allow_negative=False,
        )
        total_par2_score = par2_score(
            by_fn,
            (
                "egglog-encoding-time",
                "egglog-solver-time",
                "gurobi-encoding-time",
                "gurobi-solving-time",
            ),
            ("egglog-status", "gurobi-status"),
            PAR2_TIMEOUT_SECONDS,
        )

        egglog_to, egglog_mo = counts["egglog"]
        ge_to, ge_mo = counts["gurobi-encoding"]
        g_to, g_mo = counts["gurobi"]
        gurobi_to, gurobi_mo = (ge_to + g_to, ge_mo + g_mo)
        timeout_summary_by_name[basename] = (
            egglog_avg_time,
            egglog_to,
            egglog_mo,
            gurobi_avg_time,
            gurobi_to,
            gurobi_mo,
            total_par2_score,
        )

    if not variant_maps:
        print(
            "No variant JSON files from LATEX_METHOD_ORDER were found; nothing to write.",
            file=sys.stderr,
        )
        return 1

    latex_out = write_latex_tables(
        results_dir=results_dir,
        control_map=control_map,
        variant_maps=variant_maps,
        virtual_best_by_metric=virtual_best_by_metric,
        timeout_summary=timeout_summary_by_name,
    )
    print(f"Wrote LaTeX table: {latex_out}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
